export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Array<Record<string, unknown>>;
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Array<Record<string, unknown>>>;
}

const DEFAULT_DELIMITER = ",";
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = "\n";

const matchesAt = (input: string, index: number, token: string): boolean => {
  if (!token) {
    return false;
  }
  return input.slice(index, index + token.length) === token;
};

const coerceValue = (value: string): unknown => {
  if (value === "") {
    return null;
  }

  const trimmed = value.trim();
  if (trimmed === "") {
    return null;
  }

  const lower = trimmed.toLowerCase();
  if (lower === "null") {
    return null;
  }
  if (lower === "true") {
    return true;
  }
  if (lower === "false") {
    return false;
  }

  const numberPattern = /^[+-]?(?:\d+\.?\d*|\.\d+)(?:[eE][+-]?\d+)?$/;
  if (numberPattern.test(trimmed)) {
    const numberValue = Number(trimmed);
    if (Number.isFinite(numberValue)) {
      return numberValue;
    }
  }

  return value;
};

class CSVResultImpl implements CSVResult {
  rows: Array<Record<string, unknown>>;
  headers: string[];
  errors: CSVError[];

  constructor(
    rows: Array<Record<string, unknown>>,
    headers: string[],
    errors: CSVError[]
  ) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult {
    return new CSVResultImpl(this.rows.filter(predicate), this.headers, this.errors);
  }

  sum(column: string): number {
    return this.rows.reduce((total, row) => {
      const value = row[column];
      return typeof value === "number" && Number.isFinite(value)
        ? total + value
        : total;
    }, 0);
  }

  average(column: string): number {
    let total = 0;
    let count = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === "number" && Number.isFinite(value)) {
        total += value;
        count += 1;
      }
    }
    return count === 0 ? 0 : total / count;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<unknown, Array<Record<string, unknown>>> {
    const groups = new Map<unknown, Array<Record<string, unknown>>>();
    for (const row of this.rows) {
      const key = row[column];
      const group = groups.get(key);
      if (group) {
        group.push(row);
      } else {
        groups.set(key, [row]);
      }
    }
    return groups;
  }
}

export const parseCSV = (input: string, options: CSVOptions = {}): CSVResult => {
  const delimiter = options.delimiter ?? DEFAULT_DELIMITER;
  const quoteChar = options.quoteChar ?? DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator ?? DEFAULT_LINE_SEPARATOR;

  const rows: string[][] = [];
  const errors: CSVError[] = [];

  if (!input) {
    return new CSVResultImpl([], [], []);
  }

  let currentField = "";
  let currentRow: string[] = [];
  let inQuotes = false;
  let rowIndex = 1;

  for (let i = 0; i < input.length; i += 1) {
    if (inQuotes) {
      if (matchesAt(input, i, quoteChar)) {
        const nextIndex = i + quoteChar.length;
        if (matchesAt(input, nextIndex, quoteChar)) {
          currentField += quoteChar;
          i += quoteChar.length;
        } else {
          inQuotes = false;
          i += quoteChar.length - 1;
        }
      } else {
        currentField += input[i];
      }
      continue;
    }

    if (matchesAt(input, i, delimiter)) {
      currentRow.push(currentField);
      currentField = "";
      i += delimiter.length - 1;
      continue;
    }

    if (matchesAt(input, i, lineSeparator)) {
      currentRow.push(currentField);
      rows.push(currentRow);
      currentField = "";
      currentRow = [];
      rowIndex += 1;
      i += lineSeparator.length - 1;
      continue;
    }

    if (matchesAt(input, i, quoteChar)) {
      if (currentField.length === 0) {
        inQuotes = true;
      } else {
        errors.push({ row: rowIndex, message: "Unexpected quote character." });
        currentField += quoteChar;
      }
      i += quoteChar.length - 1;
      continue;
    }

    currentField += input[i];
  }

  if (inQuotes) {
    errors.push({ row: rowIndex, message: "Unclosed quoted field." });
  }

  if (
    currentRow.length > 0 ||
    currentField.length > 0 ||
    !input.endsWith(lineSeparator)
  ) {
    currentRow.push(currentField);
    rows.push(currentRow);
  }

  if (rows.length === 0) {
    return new CSVResultImpl([], [], errors);
  }

  const headers = rows[0];
  const parsedRows: Array<Record<string, unknown>> = [];

  for (let i = 1; i < rows.length; i += 1) {
    const row = rows[i];
    if (row.length !== headers.length) {
      errors.push({
        row: i + 1,
        message: `Expected ${headers.length} fields but found ${row.length}.`,
      });
    }

    const record: Record<string, unknown> = {};
    for (let j = 0; j < headers.length; j += 1) {
      const rawValue = row[j] ?? "";
      record[headers[j]] = coerceValue(rawValue);
    }
    parsedRows.push(record);
  }

  return new CSVResultImpl(parsedRows, headers, errors);
};

import { parseCSV } from "./csv-parser";

type AssertionError = {
  message: string;
};

const assert = (condition: boolean, message: string): void => {
  if (!condition) {
    const error = new Error(message) as Error & AssertionError;
    error.message = message;
    throw error;
  }
};

const deepEqual = (a: unknown, b: unknown): boolean => {
  if (a === b) {
    return true;
  }

  if (a instanceof Map && b instanceof Map) {
    if (a.size !== b.size) {
      return false;
    }
    for (const [key, value] of a.entries()) {
      if (!b.has(key) || !deepEqual(value, b.get(key))) {
        return false;
      }
    }
    return true;
  }

  if (Array.isArray(a) && Array.isArray(b)) {
    if (a.length !== b.length) {
      return false;
    }
    for (let i = 0; i < a.length; i += 1) {
      if (!deepEqual(a[i], b[i])) {
        return false;
      }
    }
    return true;
  }

  if (
    a &&
    b &&
    typeof a === "object" &&
    typeof b === "object" &&
    !Array.isArray(a) &&
    !Array.isArray(b)
  ) {
    const keysA = Object.keys(a as Record<string, unknown>);
    const keysB = Object.keys(b as Record<string, unknown>);
    if (keysA.length !== keysB.length) {
      return false;
    }
    for (const key of keysA) {
      if (!deepEqual(
        (a as Record<string, unknown>)[key],
        (b as Record<string, unknown>)[key]
      )) {
        return false;
      }
    }
    return true;
  }

  return false;
};

const assertDeepEqual = (actual: unknown, expected: unknown, message: string): void => {
  assert(deepEqual(actual, expected), message);
};

const runTests = (): void => {
  const basic = parseCSV("name,age\nAlice,30\nBob,25");
  assertDeepEqual(basic.headers, ["name", "age"], "Basic headers mismatch.");
  assertDeepEqual(
    basic.rows,
    [
      { name: "Alice", age: 30 },
      { name: "Bob", age: 25 },
    ],
    "Basic rows mismatch."
  );

  const quoted = parseCSV("name,comment\n\"Alice\",\"Hello, world\"\n\"Bob\",\"Hi\"");
  assertDeepEqual(
    quoted.rows,
    [
      { name: "Alice", comment: "Hello, world" },
      { name: "Bob", comment: "Hi" },
    ],
    "Quoted fields with commas failed."
  );

  const escaped = parseCSV("name,quote\nAlice,\"He said \"\"Hello\"\"\"");
  assertDeepEqual(
    escaped.rows,
    [{ name: "Alice", quote: "He said \"Hello\"" }],
    "Escaped quote parsing failed."
  );

  const custom = parseCSV("id;value|1;2|3;4", {
    delimiter: ";",
    lineSeparator: "|",
  });
  assertDeepEqual(
    custom.rows,
    [
      { id: 1, value: 2 },
      { id: 3, value: 4 },
    ],
    "Custom delimiter parsing failed."
  );

  const coercion = parseCSV("a,b,c,d,e,f\n1,2.5,true,FALSE,null,");
  assertDeepEqual(
    coercion.rows,
    [
      {
        a: 1,
        b: 2.5,
        c: true,
        d: false,
        e: null,
        f: null,
      },
    ],
    "Type coercion failed."
  );

  const malformed = parseCSV("a,b\n1,2,3\n\"broken", {
    lineSeparator: "\n",
  });
  assert(malformed.errors.length === 2, "Malformed rows should create errors.");
  assertDeepEqual(
    malformed.errors.map((error) => error.row),
    [2, 3],
    "Malformed row numbers incorrect."
  );

  const filterResult = parseCSV("name,age\nAlice,40\nBob,20\nCara,50");
  const filtered = filterResult.filter((row) => (row.age as number) > 30);
  assertDeepEqual(
    filtered.rows,
    [
      { name: "Alice", age: 40 },
      { name: "Cara", age: 50 },
    ],
    "Filter did not return expected rows."
  );

  const aggregates = parseCSV("name,score,team\nAva,10,Red\nBen,20,Blue\nCia,30,Red");
  assert(aggregates.count() === 3, "Count aggregation failed.");
  assert(aggregates.sum("score") === 60, "Sum aggregation failed.");
  assert(aggregates.average("score") === 20, "Average aggregation failed.");
  const grouped = aggregates.groupBy("team");
  assert(grouped.get("Red")?.length === 2, "GroupBy failed for Red.");
  assert(grouped.get("Blue")?.length === 1, "GroupBy failed for Blue.");

  const empty = parseCSV("");
  assertDeepEqual(empty.headers, [], "Empty input headers should be empty.");
  assertDeepEqual(empty.rows, [], "Empty input rows should be empty.");

  const singleColumn = parseCSV("value\n1\n2");
  assertDeepEqual(
    singleColumn.rows,
    [{ value: 1 }, { value: 2 }],
    "Single column parsing failed."
  );

  const singleRow = parseCSV("a,b\n1,2");
  assertDeepEqual(
    singleRow.rows,
    [{ a: 1, b: 2 }],
    "Single row parsing failed."
  );

  const largeField = "a".repeat(10000);
  const largeResult = parseCSV(`col\n\"${largeField}\"`);
  assert(
    (largeResult.rows[0].col as string).length === 10000,
    "Large field parsing failed."
  );
};

runTests();

